    'pages.operasional.playbook-incident-response.item_1' => 'Severity disepakati dan owner jelas.',
    'pages.operasional.playbook-incident-response.item_10' => '<strong>Incident channel:</strong> update periodik lintas tim.',
    'pages.operasional.playbook-incident-response.item_11' => '<strong>Status page/internal broadcast:</strong> info resmi ke user/stakeholder.',
    'pages.operasional.playbook-incident-response.item_12' => '<strong>Ticket incident:</strong> sumber kebenaran tunggal (owner, severity, timeline).',
    'pages.operasional.playbook-incident-response.item_2' => 'Ada mitigasi awal atau rencana mitigasi terikat waktu.',
    'pages.operasional.playbook-incident-response.item_3' => 'Status update pertama sudah terkirim.',
    'pages.operasional.playbook-incident-response.item_4' => 'Timeline/log evidence mulai terdokumentasi.',
    'pages.operasional.playbook-incident-response.item_5' => 'Persentase error 5xx melewati threshold kritis.',
    'pages.operasional.playbook-incident-response.item_6' => 'Fitur transaksi inti tidak bisa dipakai user.',
    'pages.operasional.playbook-incident-response.item_7' => 'Tidak ada mitigasi efektif dalam 15 menit pertama.',
    'pages.operasional.playbook-incident-response.item_8' => 'Ada dampak finansial/regulatori atau risiko data integrity.',
    'pages.operasional.playbook-incident-response.item_9' => '<strong>War-room:</strong> koordinasi teknis real-time.',
    'pages.operasional.playbook-incident-response.lead' => 'Panduan operasional siapa melakukan apa pada 15 menit pertama incident, agar respons konsisten dan cepat.',
    'pages.operasional.playbook-incident-response.note_1' => 'Satu orang boleh memegang lebih dari satu peran pada tim kecil, tetapi IC sebaiknya tidak merangkap eksekutor utama.',
    'pages.operasional.playbook-incident-response.step_1' => '3-7 menit: kumpulkan evidence minimum (error rate, endpoint terdampak, rentang user).',
    'pages.operasional.playbook-incident-response.step_2' => '7-12 menit: jalankan mitigasi tercepat yang aman (rollback/disable feature/degrade mode).',
    'pages.operasional.playbook-incident-response.step_3' => '12-15 menit: kirim status update resmi pertama ke stakeholder.',
    'pages.operasional.playbook-incident-response.step_4' => '2. Tetapkan 4 peran minimum: IC, Ops, Comms, Scribe.',
    'pages.operasional.playbook-incident-response.step_5' => '3. Jalankan mitigasi tercepat yang reversible.',
    'pages.operasional.playbook-incident-response.step_6' => '4. Kirim update #1 maksimal menit ke-15.',
    'pages.operasional.playbook-incident-response.step_7' => '5. Simpan evidence untuk RCA/postmortem sejak awal.',
    'pages.operasional.playbook-incident-response.step_8' => '0-3 menit: triage awal, tentukan severity sementara, bentuk channel war-room.',
    'pages.operasional.playbook-incident-response.step_9' => '1. Tentukan severity sementara dalam 3 menit pertama.',
