    'pages.skema.cache-dan-deployment.item_1' => 'Meningkatkan performa startup framework dan response time.',
    'pages.skema.cache-dan-deployment.item_10' => 'Saat incident aktif tanpa hipotesis jelas terkait cache.',
    'pages.skema.cache-dan-deployment.item_11' => 'Saat traffic puncak, kecuali mitigasi benar-benar memerlukan.',
    'pages.skema.cache-dan-deployment.item_12' => 'Gunakan pendekatan targeted dulu sebelum clear total.',
    'pages.skema.cache-dan-deployment.item_13' => '<strong>Config tidak berubah:</strong> cek <code>.env</code> dan jalankan <code>config:cache</code> ulang.',
    'pages.skema.cache-dan-deployment.item_14' => '<strong>Route error setelah cache:</strong> cari route closure, ubah ke controller action, lalu cache ulang.',
    'pages.skema.cache-dan-deployment.item_15' => '<strong>View lama masih tampil:</strong> jalankan <code>view:clear</code> lalu <code>view:cache</code>.',
    'pages.skema.cache-dan-deployment.item_16' => '<strong>Queue pakai code lama:</strong> jalankan <code>queue:restart</code> dan cek supervisor status.',
    'pages.skema.cache-dan-deployment.item_17' => 'Checklist migration impact (tabel besar, lock risk, durasi estimasi).',
    'pages.skema.cache-dan-deployment.item_18' => 'Konfirmasi backup/restore readiness.',
    'pages.skema.cache-dan-deployment.item_19' => 'Konfirmasi kompatibilitas aplikasi saat transisi skema.',
    'pages.skema.cache-dan-deployment.item_2' => 'Mengurangi risiko human error saat release.',
    'pages.skema.cache-dan-deployment.item_20' => 'PIC release dan PIC data menandatangani approval.',
    'pages.skema.cache-dan-deployment.item_21' => 'Deploy reguler hanya pada jam operasi yang disepakati tim.',
    'pages.skema.cache-dan-deployment.item_22' => 'Hindari deploy saat puncak trafik bisnis.',
    'pages.skema.cache-dan-deployment.item_23' => 'Freeze window diberlakukan saat event bisnis kritikal.',
    'pages.skema.cache-dan-deployment.item_24' => 'Emergency deploy di luar window wajib status incident + approval IC.',
    'pages.skema.cache-dan-deployment.item_3' => 'Menjaga deployment konsisten, repeatable, dan mudah rollback.',
    'pages.skema.cache-dan-deployment.item_4' => 'Membedakan kapan perlu regenerate cache dan kapan perlu clear cache total.',
    'pages.skema.cache-dan-deployment.item_5' => 'Perubahan config tidak terbaca meski file sudah update.',
    'pages.skema.cache-dan-deployment.item_6' => 'Route baru tidak muncul atau route lama masih dipakai.',
    'pages.skema.cache-dan-deployment.item_7' => 'Tampilan Blade lama masih tampil setelah deploy.',
    'pages.skema.cache-dan-deployment.item_8' => 'Issue anomali setelah rollback/forward deployment.',
    'pages.skema.cache-dan-deployment.item_9' => 'Saat sistem stabil dan tidak ada indikasi stale cache.',
    'pages.skema.cache-dan-deployment.hero_title' => 'Skema & Arsitektur Cache & Deployment (Release Operations Blueprint)',
    'pages.skema.cache-dan-deployment.hero_lead' => 'Strategi config/route/view cache, runbook deployment production, checklist pra & pasca-release, SOP rollback, troubleshooting stale cache, serta gate approval rilis.',
    'pages.skema.cache-dan-deployment.lead' => '<code>config:cache</code>, <code>route:cache</code>, <code>view:cache</code>, kapan clear cache, dan checklist release.',
    'pages.skema.cache-dan-deployment.note_1' => 'Jika memakai supervisor/horizon/queue worker, pastikan worker membaca code terbaru setelah deploy.',
    'pages.skema.cache-dan-deployment.note_2' => 'Jika salah satu step gagal, proses berhenti dan status release berubah menjadi failed untuk mencegah partial deploy.',
    'pages.skema.cache-dan-deployment.step_1' => '<code>php artisan route:cache</code>: jalankan jika seluruh route kompatibel cache (tanpa closure).',
    'pages.skema.cache-dan-deployment.step_10' => '3. Pantau log aplikasi 10-30 menit pertama.',
    'pages.skema.cache-dan-deployment.step_11' => '4. Validasi worker/cron berjalan dengan code terbaru.',
    'pages.skema.cache-dan-deployment.step_12' => '5. Kirim status release selesai ke stakeholder.',
    'pages.skema.cache-dan-deployment.step_13' => '<strong>Rule wajib:</strong> urutan command harus mengikuti runbook resmi tanpa skip step.',
    'pages.skema.cache-dan-deployment.step_14' => '<strong>Rule wajib:</strong> migration membutuhkan approval gate minimal 2 pihak (PIC release + PIC data/tech lead).',
    'pages.skema.cache-dan-deployment.step_15' => '<strong>Rule wajib:</strong> setiap release harus punya rollback plan terdokumentasi sebelum eksekusi.',
    'pages.skema.cache-dan-deployment.step_16' => '<strong>Rule wajib:</strong> release di luar time-window hanya boleh untuk emergency dengan approval incident commander.',
    'pages.skema.cache-dan-deployment.step_17' => '<strong>Rule wajib:</strong> post-release smoke test dan observability check harus selesai sebelum status “done”.',
    'pages.skema.cache-dan-deployment.step_18' => '<strong>Rule opsional:</strong> gunakan canary/blue-green untuk fitur berisiko tinggi.',
    'pages.skema.cache-dan-deployment.step_19' => 'Gate 2 - Migration: approval lengkap dan migration sukses tanpa error.',
    'pages.skema.cache-dan-deployment.step_2' => '<code>php artisan view:cache</code>: jalankan untuk mempercepat first-hit Blade.',
    'pages.skema.cache-dan-deployment.step_20' => 'Gate 3 - Cache: config/route/view cache regenerate sukses.',
    'pages.skema.cache-dan-deployment.step_21' => 'Gate 4 - Runtime: worker restart sukses dan health check hijau.',
    'pages.skema.cache-dan-deployment.step_22' => 'Gate 5 - Post-check: smoke test endpoint kritikal lolos.',
    'pages.skema.cache-dan-deployment.step_23' => 'Jika salah satu gate fail, lakukan rollback sesuai runbook.',
    'pages.skema.cache-dan-deployment.step_24' => '<code>php artisan config:cache</code>: jalankan setiap release setelah update konfigurasi/aplikasi.',
    'pages.skema.cache-dan-deployment.step_25' => '1. Pastikan branch release sudah freeze dan tervalidasi QA.',
    'pages.skema.cache-dan-deployment.step_26' => '1. Smoke test login, dashboard, transaksi utama, dan halaman error.',
    'pages.skema.cache-dan-deployment.step_27' => '<strong>Rule wajib:</strong> deployment production hanya melalui pipeline/skrip baku, bukan command manual acak.',
    'pages.skema.cache-dan-deployment.step_28' => 'Gate 1 - Preflight: semua dependency/build lulus.',
    'pages.skema.cache-dan-deployment.step_3' => '<code>php artisan optimize:clear</code>: gunakan hanya saat troubleshooting cache stale atau sebelum regenerate penuh.',
    'pages.skema.cache-dan-deployment.step_4' => 'Urutan aman: clear seperlunya -> regenerate cache -> smoke test.',
    'pages.skema.cache-dan-deployment.step_5' => '2. Verifikasi migration aman dan punya rollback plan.',
    'pages.skema.cache-dan-deployment.step_6' => '3. Verifikasi route kompatibel untuk <code>route:cache</code>.',
    'pages.skema.cache-dan-deployment.step_7' => '4. Siapkan maintenance message/feature flag jika perlu.',
    'pages.skema.cache-dan-deployment.step_8' => '5. Tentukan PIC deploy, PIC verifikasi, dan PIC komunikasi.',
    'pages.skema.cache-dan-deployment.step_9' => '2. Pantau metrik: error rate 4xx/5xx, latency, queue backlog.',
    'pages.skema.cache-dan-deployment.warn_1' => 'Clear total secara impulsif bisa menambah load startup dan memperpanjang waktu recovery.',
