    // Pages - Operasional Panduan Tambah Halaman
    'pages.operasional.panduan-tambah-halaman.hero_title' => 'Panduan Operasional: Cara Menambah Halaman Baru',
    'pages.operasional.panduan-tambah-halaman.hero_lead' => 'Panduan praktis langkah demi langkah untuk developer dalam menambah halaman baru, membuat controller & form partial, mengonfigurasi navigasi, serta menerapkan standar CRUD.',
    'pages.operasional.panduan-tambah-halaman.lead' => 'Panduan alur kerja developer untuk menambah halaman baru, registrasi route otomatis, preservasi layout core, dan standarisasi CRUD.',
    'pages.operasional.panduan-tambah-halaman.chip_1' => 'Zero Route Config',
    'pages.operasional.panduan-tambah-halaman.chip_2' => 'Multi-Tab Single Route',
    'pages.operasional.panduan-tambah-halaman.chip_3' => 'Responsive Table Native',
    'pages.operasional.panduan-tambah-halaman.chip_4' => 'SwalHelper Global',
    'pages.operasional.panduan-tambah-halaman.heading_1' => 'Workflow Developer Harian (Tambah Halaman)',
    'pages.operasional.panduan-tambah-halaman.heading_2' => 'Contoh Penamaan & Routing Otomatis',
    'pages.operasional.panduan-tambah-halaman.heading_3' => 'Aturan Layout Multi-Tab & Core Layout',
    'pages.operasional.panduan-tambah-halaman.heading_4' => 'Aturan Pembuatan Tabel Responsif',
    'pages.operasional.panduan-tambah-halaman.heading_5' => 'Struktur Controller, Model & Form Partial',
    'pages.operasional.panduan-tambah-halaman.heading_6' => 'Notifikasi CRUD JS Helper (SwalHelper)',
    'pages.operasional.panduan-tambah-halaman.heading_7' => 'Top Tooltips & Modal Trigger Wrapper',
    'pages.operasional.panduan-tambah-halaman.heading_8' => 'Command Inspeksi & Verifikasi Rilis',
    'pages.operasional.panduan-tambah-halaman.heading_9' => 'Standar & Rule Wajib Tim (Strict Page Onboarding)',
    'pages.operasional.panduan-tambah-halaman.step_5' => '1. Buat file Blade baru di <code>resources/views/pages/&lt;folder&gt;/&lt;halaman&gt;.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_1' => '2. Route GET &amp; URL langsung terbentuk otomatis via <code>routes/menu-temp.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_2' => '3. Buat Controller &amp; Model sejajar di <code>App\\Http\\Controllers\\&lt;Folder&gt;\\&lt;Halaman&gt;Controller</code>.',
    'pages.operasional.panduan-tambah-halaman.step_3' => '4. Ekstrak Form CRUD ke <code>resources/views/pages/&lt;folder&gt;/partials/&lt;fitur&gt;-form.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_4' => '5. Daftarkan menu navigasi di <code>config/sidebar/_sidebar_*.php</code> dan <code>lang/*/menu.php</code>.',
    'pages.operasional.panduan-tambah-halaman.step_6' => '<strong>Rule Wajib Zero Layout Mutation:</strong> Layout core &amp; menu seeder dilarang diubah hanya untuk membuat sub-tab.',
    'pages.operasional.panduan-tambah-halaman.step_7' => '<strong>Rule Wajib Mirror Folder Structure:</strong> Lokasi Controller, Model, &amp; Form Request wajib presisi sejajar dengan lokasi view Blade.',
    'pages.operasional.panduan-tambah-halaman.step_8' => '<strong>Rule Wajib SwalHelper Only:</strong> Seluruh notifikasi SweetAlert wajib menggunakan global helper <code>SwalHelper</code>.',
    'pages.operasional.panduan-tambah-halaman.step_9' => '<strong>Rule Wajib Top Tooltips:</strong> Setiap tombol ikon-saja (btn-icon) wajib menggunakan top tooltip &amp; pembungkus modal trigger.',
    'pages.operasional.panduan-tambah-halaman.item_1' => '<strong>Jangan Mengubah Layout Core:</strong> Dilarang mengubah <code>_menu-item.blade.php</code>, <code>navs.blade.php</code>, atau seeder menu untuk sub-tab.',
    'pages.operasional.panduan-tambah-halaman.item_2' => '<strong>Arsitektur Multi-Tab Single-Route:</strong> Gunakan rute tunggal (misal <code>/profil-pengguna?tab=...</code>) dan <code>@@include</code> tab partial.',
    'pages.operasional.panduan-tambah-halaman.item_3' => '<strong>Integritas Partial Blade:</strong> File partial tab TIDAK boleh berisi <code>@@endsection</code>, <code>@@extends</code>, atau tag closing <code>&lt;/div&gt;</code> utama.',
    'pages.operasional.panduan-tambah-halaman.item_4' => '<strong>Script Bundles:</strong> <code>@@section(\'scripts\')</code> wajib memuat bundel JS pendukung (<code>widgets.bundle.js</code>, <code>datatables.bundle.js</code>).',
    'pages.operasional.panduan-tambah-halaman.item_5' => '<strong>Tanpa Custom CSS:</strong> Dilarang membuat tag <code>&lt;style&gt;</code> custom. Gunakan 100% kelas Metronic &amp; Bootstrap 5.',
    'pages.operasional.panduan-tambah-halaman.item_6' => '<strong>Pembungkus Responsif Bawaan:</strong> Wajib membungkus tabel data dengan <code>&lt;div class="table-responsive"&gt;</code>.',
    'pages.operasional.panduan-tambah-halaman.item_7' => '<strong>Menjaga Lebar Kolom:</strong> Gunakan kelas min-width bawaan Metronic (<code>min-w-200px</code>, <code>min-w-150px</code>, <code>min-w-125px</code>) pada <code>&lt;th&gt;</code>.',
    'pages.operasional.panduan-tambah-halaman.item_8' => '<strong>Struktur Folder Sejajar:</strong> Controllers &amp; Models wajib dibuat di sub-folder yang mencerminkan struktur view Blade.',
    'pages.operasional.panduan-tambah-halaman.item_9' => '<strong>Pemisahan Form Partial:</strong> Form modal CRUD wajib dipisahkan di <code>resources/views/pages/&lt;folder&gt;/partials/&lt;fitur&gt;-form.blade.php</code>.',
    'pages.operasional.panduan-tambah-halaman.item_10' => '<strong>Validasi Form Request Mirroring:</strong> Aturan validasi wajib dipisahkan ke <code>App\\Http\\Requests\\&lt;SubFolder&gt;\\&lt;FeatureRequest&gt;.php</code>.',
    'pages.operasional.panduan-tambah-halaman.item_11' => '<strong>Global SwalHelper:</strong> Notifikasi CRUD wajib menggunakan <code>SwalHelper.success()</code>, <code>SwalHelper.error()</code>, <code>SwalHelper.validationError(xhr)</code>, &amp; <code>SwalHelper.confirmDelete()</code>.',
    'pages.operasional.panduan-tambah-halaman.item_12' => '<strong>Mandatory Top Tooltips:</strong> Setiap <code>btn-icon</code> wajib memakai <code>data-bs-toggle="tooltip" data-bs-placement="top" title="..."</code>.',
    'pages.operasional.panduan-tambah-halaman.item_13' => '<strong>Modal Trigger Tooltip Wrapper:</strong> Bungkus tombol modal trigger dengan <code>&lt;span data-bs-toggle="tooltip" data-bs-placement="top" title="..."&gt;</code> untuk mencegah konflik atribut.',
    'pages.operasional.panduan-tambah-halaman.note_1' => 'File Blade yang diawali dengan underscore (_) atau berada di dalam folder partials/ diabaikan secara otomatis oleh auto route generator.',
    'pages.operasional.panduan-tambah-halaman.warn_1' => 'Selalu jalankan php artisan view:clear dan route:clear jika route atau tampilan baru tidak langsung merespons di browser.',

    // Pages - Operasional Panduan Tambah Menu
    'pages.operasional.panduan-tambah-menu.hero_title' => 'Panduan Operasional: Cara Menambah Menu Navigasi',
    'pages.operasional.panduan-tambah-menu.hero_lead' => 'Panduan praktis langkah demi langkah untuk mengonfigurasi menu sidebar & header, modularisasi seeder per kategori, penggunaan route vs href, atribut opsional (badge, target, icon), serta verifikasi active state.',
    'pages.operasional.panduan-tambah-menu.lead' => 'Panduan alur kerja developer untuk menambahkan item menu baru pada navigasi sidebar dan header aplikasi.',
    'pages.operasional.panduan-tambah-menu.chip_1' => 'Declarative Array Config',
    'pages.operasional.panduan-tambah-menu.chip_2' => 'Modular Seeder per Kategori',
    'pages.operasional.panduan-tambah-menu.chip_3' => 'Route vs Href Strategy',
    'pages.operasional.panduan-tambah-menu.chip_4' => 'Optional Features (Badge, Target)',
    'pages.operasional.panduan-tambah-menu.heading_1' => '3 Langkah Utama Tambah Menu Baru',
    'pages.operasional.panduan-tambah-menu.heading_2' => 'Modularisasi Config & Menu Seeder per Kategori',
    'pages.operasional.panduan-tambah-menu.heading_3' => 'Panduan Keputusan: Kapan Pakai route vs href',
    'pages.operasional.panduan-tambah-menu.heading_4' => 'Atribut & Fitur Opsional Konfigurasi Menu',
    'pages.operasional.panduan-tambah-menu.heading_5' => 'Kontrak Struktur Data Array Menu PHP',
    'pages.operasional.panduan-tambah-menu.heading_6' => 'Mesin Normalisasi Key Translasi Judul',
    'pages.operasional.panduan-tambah-menu.heading_7' => 'Aturan & Evaluasi Active State',
    'pages.operasional.panduan-tambah-menu.heading_8' => 'Panduan Debug & Troubleshooting Menu',
    'pages.operasional.panduan-tambah-menu.heading_9' => 'Standar & Rule Wajib Tim (Strict Menu Operations)',
    'pages.operasional.panduan-tambah-menu.step_3' => '1. Judul string di config diubah otomatis ke format snake_case <code>menu.*</code>.',
    'pages.operasional.panduan-tambah-menu.step_1' => '2. Blade renderer mencari key tersebut di <code>lang/&lt;locale&gt;/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.step_2' => '3. Jika key tidak ditemukan, sistem fallback me-render teks judul asli tanpa error.',
    'pages.operasional.panduan-tambah-menu.item_1' => 'Edit berkas konfigurasi domain yang sesuai di <code>config/sidebar/_sidebar_*.php</code> atau <code>config/header/_header_*.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_2' => 'Tambahkan key translasi judul di <code>lang/en/menu.php</code> dan <code>lang/id/menu.php</code> sesuai normalisasi <code>menu.*</code>.',
    'pages.operasional.panduan-tambah-menu.item_3' => 'Verifikasi keaktifan route (<code>php artisan route:list</code>) dan tes active state parent-child pada desktop &amp; mobile.',
    'pages.operasional.panduan-tambah-menu.item_4' => 'Leaf menu aktif secara otomatis saat <code>request()->routeIs($route . \'*\')</code> bernilai true.',
    'pages.operasional.panduan-tambah-menu.item_5' => 'Parent menu otomatis mendapat class <code>active</code>, <code>here</code>, dan <code>show</code> secara rekursif jika minimal satu child di bawahnya aktif.',
    'pages.operasional.panduan-tambah-menu.item_6' => 'Pada mode dropdown, active state child tetap mengevaluasi route wildcard untuk membuka flyout.',
    'pages.operasional.panduan-tambah-menu.item_7' => '<strong>Menu Tidak Tampil:</strong> Periksa pendaftaran file config di <code>_menu.blade.php</code> dan pastikan tidak ada parse error pada array PHP.',
    'pages.operasional.panduan-tambah-menu.item_8' => '<strong>Judul Tidak Tertranslate:</strong> Cek nama key <code>menu.*</code> hasil normalisasi dan pastikan key terdaftar di <code>lang/en/menu.php</code> dan <code>lang/id/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_9' => '<strong>Parent Tidak Auto-Open:</strong> Cek kecocokan route name child dan pastikan wildcard <code>routeIs</code> menutup seluruh sub-route.',
    'pages.operasional.panduan-tambah-menu.item_10' => '<strong>Ikon Pecah / Kosong:</strong> Pastikan class ikon Keenicons valid dan jumlah <code>paths</code> sesuai dengan span duotone.',
    'pages.operasional.panduan-tambah-menu.item_11' => '<strong>Rule Wajib Zero Core Layout Edit:</strong> Dilarang mengubah partial core (<code>_menu-item.blade.php</code>) atau seeder database hanya untuk menambah menu statis.',
    'pages.operasional.panduan-tambah-menu.item_12' => '<strong>Rule Wajib Bilingual Parity:</strong> Setiap item menu baru wajib didaftarkan di <code>lang/en/menu.php</code> dan <code>lang/id/menu.php</code>.',
    'pages.operasional.panduan-tambah-menu.item_13' => '<strong>Rule Wajib Mobile Drawer Test:</strong> Pengujian menu baru wajib dilakukan pada tampilan desktop (hover/accordion) dan mobile (click drawer).',
    'pages.operasional.panduan-tambah-menu.item_14' => '<strong>Rule Wajib Route Validation:</strong> Pastikan route target sudah terdaftar dan aktif sebelum diajukan ke Pull Request.',
    'pages.operasional.panduan-tambah-menu.item_15' => '<strong>Modularisasi Config Sidebar/Header:</strong> Struktur menu statis dipisah per domain di <code>config/sidebar/_sidebar_&lt;kategori&gt;.php</code> (dashboard, pages, apps, layouts, helps).',
    'pages.operasional.panduan-tambah-menu.item_16' => '<strong>Modularisasi Menu Seeder Database:</strong> Untuk menu dinamis berbasis database/permission, seeder dipisahkan per kategori di <code>config/menu_seeder/&lt;kategori&gt;_seeder.php</code> dan di-seed via <code>php artisan db:seed --class=MenuSeeder</code>.',
    'pages.operasional.panduan-tambah-menu.item_17' => '<strong>Preservasi Seeder Core:</strong> Dilarang mengedit atau merusak file seeder core secara paksa. Tambahkan seeder terpisah jika menambah modul baru.',
    'pages.operasional.panduan-tambah-menu.item_18' => '<strong>Gunakan route (Rekomendasi Internal):</strong> Gunakan <code>\'route\' =&gt; \'nama.route\'</code> untuk seluruh tautan halaman internal Laravel. Keuntungan: aman dari refactoring URL path, mendukung active state otomatis <code>request()-&gt;routeIs(...)</code>, dan terintegrasi route cache.',
    'pages.operasional.panduan-tambah-menu.item_19' => '<strong>Gunakan href (Tautan Eksternal/Anchor):</strong> Gunakan <code>\'href\' =&gt; \'https://...\'</code> hanya untuk tautan URL eksternal, anchor ID halaman (<code>#section</code>), atau URL statis yang tidak memiliki named route.',
    'pages.operasional.panduan-tambah-menu.item_20' => '<strong>Keamanan Tautan Eksternal:</strong> Setiap penggunaan <code>href</code> ke domain luar wajib menyertakan atribut <code>\'target\' =&gt; \'_blank\'</code> demi keamanan (mencegah reverse tabnabbing) dan kenyamanan pengguna.',
    'pages.operasional.panduan-tambah-menu.item_21' => '<strong>Lencana Status (badge):</strong> Menampilkan badge warna di samping judul menu, contoh: <code>\'badge\' =&gt; [\'text\' =&gt; \'New\', \'class\' =&gt; \'badge-light-success\']</code>.',
    'pages.operasional.panduan-tambah-menu.item_22' => '<strong>Ikon Duotone Custom (icon):</strong> Menentukan ikon Keenicons duotone, contoh: <code>\'icon\' =&gt; [\'element\' =&gt; \'ki-duotone ki-element-11\', \'paths\' =&gt; 4]</code>.',
    'pages.operasional.panduan-tambah-menu.item_23' => '<strong>Mode Submenu Flyout (dropdown):</strong> Set <code>\'dropdown\' =&gt; true</code> pada parent node untuk mengubah tampilan submenu dari accordion menjadi melayang/flyout.',
    'pages.operasional.panduan-tambah-menu.item_24' => '<strong>Target Tab Baru (target):</strong> Set <code>\'target\' =&gt; \'_blank\'</code> untuk membuka tautan pada tab browser baru.',
    'pages.operasional.panduan-tambah-menu.item_25' => '<strong>Indikator Titik (bullet):</strong> Set <code>\'bullet\' =&gt; true</code> pada leaf item untuk menampilkan titik indikator di samping teks.',
    'pages.operasional.panduan-tambah-menu.item_26' => '<strong>Fitur Show More/Less (menus_dashboard_collapsed):</strong> Array khusus pada menu dashboard untuk menyembunyikan item tambahan yang dapat di-expand secara interaktif.',
    'pages.operasional.panduan-tambah-menu.note_1' => 'Minimal atribut leaf item: title + route atau title + href. Parent node wajib menyertakan array children[].',
    'pages.operasional.panduan-tambah-menu.note_2' => 'Jalankan php artisan config:clear dan php artisan view:clear jika perubahan menu tidak langsung muncul di browser.',

    // Pages - Operasional Konvensi Penamaan
    'pages.operasional.konvensi-penamaan.hero_title' => 'Panduan Operasional: Konvensi Penamaan (Naming Conventions)',
    'pages.operasional.konvensi-penamaan.hero_lead' => 'Standar aturan penamaan berkas Blade, Controller, Model, Form Request, Route, Database, Translation Key, dan JavaScript helper dalam arsitektur aplikasi.',
    'pages.operasional.konvensi-penamaan.lead' => 'Panduan praktis aturan penamaan berkas dan entitas sistem untuk menjaga konsistensi codebase developer.',
    'pages.operasional.konvensi-penamaan.chip_1' => 'kebab-case for Blade & Route',
    'pages.operasional.konvensi-penamaan.chip_2' => 'PascalCase for Controller & Model',
    'pages.operasional.konvensi-penamaan.chip_3' => 'snake_case for DB & i18n',
    'pages.operasional.konvensi-penamaan.chip_4' => 'camelCase for JS & Methods',
    'pages.operasional.konvensi-penamaan.heading_1' => 'Konvensi View Blade, Partial & Tab (kebab-case)',
    'pages.operasional.konvensi-penamaan.heading_2' => 'Konvensi Controller, Model & Form Request (PascalCase Mirror)',
    'pages.operasional.konvensi-penamaan.heading_3' => 'Konvensi Route Name & URL Path (kebab-case)',
    'pages.operasional.konvensi-penamaan.heading_4' => 'Konvensi Database Schema & Migration (snake_case)',
    'pages.operasional.konvensi-penamaan.heading_5' => 'Konvensi Translation Keys i18n (snake_case)',
    'pages.operasional.konvensi-penamaan.heading_6' => 'Konvensi Method Controller & JS Helper (camelCase / PascalCase)',
    'pages.operasional.konvensi-penamaan.heading_7' => 'Ringkasan Matriks Konvensi Penamaan Codebase',
    'pages.operasional.konvensi-penamaan.heading_8' => 'Checklist & Verifikasi Operasional Penamaan',
    'pages.operasional.konvensi-penamaan.item_1' => '<strong>View Blade Utama:</strong> Nama berkas Blade wajib menggunakan <code>kebab-case</code> di dalam sub-folder fitur (contoh: <code>resources/views/pages/appsupport/app-profil.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_2' => '<strong>Form Partial CRUD:</strong> Berkas partial modal form wajib ditaruh di sub-folder <code>partials/</code> dengan akhiran <code>-form.blade.php</code> (contoh: <code>partials/app-profil-form.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_3' => '<strong>Partial Sub-Tab:</strong> Berkas partial sub-tab wajib ditaruh di sub-folder <code>tabs/</code> dan berawalan underscore <code>_</code> (contoh: <code>tabs/_keamanan.blade.php</code>).',
    'pages.operasional.konvensi-penamaan.item_4' => '<strong>Controller Mirroring:</strong> Namespace Controller wajib <code>PascalCase</code> (StudlyCaps) dan jalurnya mencerminkan folder Blade (contoh: <code>App\\Http\\Controllers\\AppSupport\\AppProfilController.php</code>).',
    'pages.operasional.konvensi-penamaan.item_5' => '<strong>Model Mirroring:</strong> Model wajib singular <code>PascalCase</code> di subfolder sejajar (contoh: <code>App\\Models\\AppSupport\\AppProfil.php</code>).',
    'pages.operasional.konvensi-penamaan.item_6' => '<strong>Form Request Validation:</strong> Berkas Form Request wajib berada di namespace sejajar dengan akhiran <code>Request</code> (contoh: <code>App\\Http\\Requests\\AppSupport\\AppProfilRequest.php</code>).',
    'pages.operasional.konvensi-penamaan.item_7' => '<strong>Route Name Format:</strong> Dipisahkan oleh titik dalam format <code>kebab-case</code> mencerminkan path hirarki (contoh: <code>help.pemrograman.operasional.konvensi-penamaan</code> atau <code>appsupport.app-profil</code>).',
    'pages.operasional.konvensi-penamaan.item_8' => '<strong>Nama Tabel DB:</strong> Menggunakan jamak (plural) <code>snake_case</code> (contoh: <code>users</code>, <code>app_profiles</code>, <code>menu_seeders</code>).',
    'pages.operasional.konvensi-penamaan.item_9' => '<strong>Primary & Foreign Key:</strong> Primary key adalah <code>id</code>, sedangkan Foreign key menggunakan tunggal (singular) <code>snake_case_id</code> (contoh: <code>user_id</code>, <code>role_id</code>).',
    'pages.operasional.konvensi-penamaan.item_10' => '<strong>Kolom Timestamp & State:</strong> Menggunakan <code>snake_case</code> (contoh: <code>created_at</code>, <code>updated_at</code>, <code>is_active</code>, <code>status_code</code>).',
    'pages.operasional.konvensi-penamaan.item_11' => '<strong>Menu Translation Key:</strong> Key menu diubah otomatis ke format <code>menu.snake_case</code> di <code>lang/*/menu.php</code> (contoh: <code>\'panduan_tambah_halaman\' =&gt; \'Tambah Halaman\'</code>).',
    'pages.operasional.konvensi-penamaan.item_12' => '<strong>Page Translation Key:</strong> Key halaman menggunakan hirarki titik <code>snake_case</code> di <code>lang/*/help.php</code> (contoh: <code>pages.operasional.konvensi-penamaan.hero_title</code>).',
    'pages.operasional.konvensi-penamaan.item_13' => '<strong>Method Controller (camelCase):</strong> Method aksi standar Laravel (contoh: <code>index()</code>, <code>store()</code>, <code>update()</code>, <code>destroy()</code>, <code>getDatatable()</code>).',
    'pages.operasional.konvensi-penamaan.item_14' => '<strong>JS Helper & Method:</strong> Nama Helper JS berupa <code>PascalCase</code> (<code>SwalHelper</code>), sedangkan method berupa <code>camelCase</code> (<code>SwalHelper.success()</code>, <code>SwalHelper.validationError(xhr)</code>).',
    'pages.operasional.konvensi-penamaan.step_1' => '1. Tentukan subfolder modul dan nama fitur (contoh: modul <code>appsupport</code>, fitur <code>app-profil</code>).',
    'pages.operasional.konvensi-penamaan.step_2' => '2. Buat View Blade <code>kebab-case</code> di <code>resources/views/pages/appsupport/app-profil.blade.php</code>.',
    'pages.operasional.konvensi-penamaan.step_3' => '3. Buat Controller <code>PascalCase</code> sejajar di <code>App\\Http\\Controllers\\AppSupport\\AppProfilController.php</code>.',
    'pages.operasional.konvensi-penamaan.step_4' => '4. Verifikasi seluruh nama file &amp; namespace dengan menjalankan <code>php artisan route:list</code> dan <code>php artisan view:clear</code>.',
    'pages.operasional.konvensi-penamaan.note_1' => 'Gunakan konsistensi penuh! Jangan sekali-kali mencampur snake_case atau camelCase pada nama berkas Blade atau nama Controller.',

    // Pages - Operasional Workflow Developer Harian
    'pages.operasional.workflow-developer-harian.hero_title' => 'Panduan Operasional: Workflow Developer Harian',
    'pages.operasional.workflow-developer-harian.hero_lead' => 'Panduan standar alur kerja harian developer mulai dari inisialisasi environment lokal, pembuatan fitur baru, registrasi navigasi bilingual, pembersihan cache, hingga checklist verifikasi pra-commit.',
    'pages.operasional.workflow-developer-harian.lead' => 'Panduan alur kerja harian tim developer untuk menjaga efisiensi, konsistensi codebase, dan kualitas rilis aplikasi.',
    'pages.operasional.workflow-developer-harian.chip_1' => 'Env Setup & Asset Build',
    'pages.operasional.workflow-developer-harian.chip_2' => 'Mirror Code Structure',
    'pages.operasional.workflow-developer-harian.chip_3' => 'Bilingual i18n Parity',
    'pages.operasional.workflow-developer-harian.chip_4' => 'Pre-commit Verification',
    'pages.operasional.workflow-developer-harian.heading_1' => 'Langkah 1: Inisialisasi Environment & Pemuatan Awal (Daily Start)',
    'pages.operasional.workflow-developer-harian.heading_2' => 'Langkah 2: Alur Pengembangan Fitur & Mirror Structure',
    'pages.operasional.workflow-developer-harian.heading_3' => 'Langkah 3: Registrasi Navigasi & Translasi i18n',
    'pages.operasional.workflow-developer-harian.heading_4' => 'Langkah 4: Command CLI Pembersihan Cache & Debugging',
    'pages.operasional.workflow-developer-harian.heading_5' => 'Langkah 5: Standarisasi UI & JS Helper (SwalHelper & Tooltips)',
    'pages.operasional.workflow-developer-harian.heading_6' => 'Langkah 6: Git Branching, Commit & PR Governance',
    'pages.operasional.workflow-developer-harian.heading_7' => 'Checklist Verifikasi Pra-Commit & Pra-Release',
    'pages.operasional.workflow-developer-harian.item_1' => '<strong>Sinkronisasi Repository:</strong> Jalankan <code>git pull origin main</code> untuk memastikan kode lokal selalu diperbarui dari branch utama.',
    'pages.operasional.workflow-developer-harian.item_2' => '<strong>Jalankan Asset Build:</strong> Jalankan <code>npm run dev</code> untuk kompilasi hot-reload CSS/JS frontend.',
    'pages.operasional.workflow-developer-harian.item_3' => '<strong>Migrasi Database:</strong> Jalankan <code>php artisan migrate</code> jika terdapat pembaharuan berkas migrasi.',
    'pages.operasional.workflow-developer-harian.item_4' => '<strong>Buat View Blade:</strong> Buat file Blade <code>kebab-case</code> di <code>resources/views/pages/&lt;folder&gt;/&lt;halaman&gt;.blade.php</code>.',
    'pages.operasional.workflow-developer-harian.item_5' => '<strong>Buat Controller &amp; Model (Mirror):</strong> Buat Controller &amp; Model di sub-folder sejajar (<code>App\\Http\\Controllers\\&lt;Folder&gt;\\&lt;Halaman&gt;Controller.php</code>).',
    'pages.operasional.workflow-developer-harian.item_6' => '<strong>Ekstrak Modal Form CRUD:</strong> Pisahkan HTML form modal ke <code>partials/&lt;fitur&gt;-form.blade.php</code> dan buat validasi Form Request.',
    'pages.operasional.workflow-developer-harian.item_7' => '<strong>Config Menu Navigasi:</strong> Tambahkan item menu di <code>config/sidebar/_sidebar_*.php</code>.',
    'pages.operasional.workflow-developer-harian.item_8' => '<strong>Translasi Bilingual (EN/ID):</strong> Wajib mendaftarkan key judul menu di <code>lang/en/menu.php</code> dan <code>lang/id/menu.php</code>.',
    'pages.operasional.workflow-developer-harian.item_9' => '<strong>Optimasi &amp; Clear Cache:</strong> Jalankan <code>php artisan optimize:clear</code> saat membuat route atau view baru.',
    'pages.operasional.workflow-developer-harian.item_10' => '<strong>Inspeksi Route Active:</strong> Jalankan <code>php artisan route:list --name=&lt;nama-route&gt;</code> untuk memverifikasi pendaftaran URL.',
    'pages.operasional.workflow-developer-harian.item_11' => '<strong>Gunakan Global SwalHelper:</strong> Gunakan <code>SwalHelper.success()</code>, <code>SwalHelper.error()</code>, dan <code>SwalHelper.validationError(xhr)</code> untuk notifikasi JS.',
    'pages.operasional.workflow-developer-harian.item_12' => '<strong>Top Tooltip Wrapper:</strong> Seluruh <code>btn-icon</code> wajib ber-tooltip top dan pembungkus <code>&lt;span&gt;</code> pada trigger modal.',
    'pages.operasional.workflow-developer-harian.item_13' => '<strong>Buat Feature Branch:</strong> Gunakan format <code>git checkout -b feature/nama-fitur</code>.',
    'pages.operasional.workflow-developer-harian.item_14' => '<strong>Pemeriksaan Sintaks PHP:</strong> Jalankan <code>php -l</code> pada file PHP yang telah diubah sebelum melakukan commit.',
    'pages.operasional.workflow-developer-harian.step_1' => '1. Tarik pembaruan kode terbaru (git pull origin main).',
    'pages.operasional.workflow-developer-harian.step_2' => '2. Buat branch fitur baru &amp; kembangkan kode mengikuti konvensi penamaan.',
    'pages.operasional.workflow-developer-harian.step_3' => '3. Jalankan pembersihan cache &amp; pengujian tampilan (desktop &amp; mobile).',
    'pages.operasional.workflow-developer-harian.step_4' => '4. Lakukan commit pesan deskriptif &amp; ajukan Pull Request ke repo utama.',
    'pages.operasional.workflow-developer-harian.note_1' => 'Dilarang keras melakukan commit langsung ke branch main! Seluruh perubahan wajib melalui Feature Branch dan pengujian Pull Request.',

    // Pages - Operasional Checklist QA Smoke Test
    'pages.operasional.checklist-qa-smoke-test.hero_title' => 'Panduan Operasional: Checklist QA & Smoke Test Pra-Release',
    'pages.operasional.checklist-qa-smoke-test.hero_lead' => 'Checklist pengujian operasional wajib pra-release untuk memverifikasi navigasi, responsivitas tabel, SwalHelper CRUD, top tooltips, dan 100% paritas bilingual.',
    'pages.operasional.checklist-qa-smoke-test.lead' => 'Panduan checklist pengujian minimal yang wajib dipenuhi sebelum fitur diajukan ke Pull Request atau rilis produksi.',
    'pages.operasional.checklist-qa-smoke-test.chip_1' => 'Navigation & Route Test',
    'pages.operasional.checklist-qa-smoke-test.chip_2' => 'Responsive Table Check',
    'pages.operasional.checklist-qa-smoke-test.chip_3' => 'SwalHelper & Tooltips',
    'pages.operasional.checklist-qa-smoke-test.chip_4' => 'Bilingual Parity Verification',
    'pages.operasional.checklist-qa-smoke-test.heading_1' => 'Checklist 1: Pengujian Navigasi & Active State Menu',
    'pages.operasional.checklist-qa-smoke-test.heading_2' => 'Checklist 2: Pengujian Responsivitas & Layout Tabel',
    'pages.operasional.checklist-qa-smoke-test.heading_3' => 'Checklist 3: Pengujian Operasional CRUD & SwalHelper',
    'pages.operasional.checklist-qa-smoke-test.heading_4' => 'Checklist 4: Pengujian Top Tooltips & Modal Trigger Wrapper',
    'pages.operasional.checklist-qa-smoke-test.heading_5' => 'Checklist 5: Pengujian Paritas Multi-Bahasa (EN & ID)',
    'pages.operasional.checklist-qa-smoke-test.heading_6' => 'Checklist 6: Command CLI Verifikasi & Pembersihan Cache',
    'pages.operasional.checklist-qa-smoke-test.heading_7' => 'Gatekeeper QA & Standar Lolos Rilis (Release Approval)',
    'pages.operasional.checklist-qa-smoke-test.item_1' => '<strong>Akses URL &amp; Route:</strong> Seluruh halaman baru dapat dibuka tanpa error HTTP 404, 500, atau kecacatan layout.',
    'pages.operasional.checklist-qa-smoke-test.item_2' => '<strong>Active Highlight:</strong> Menu sidebar dan header secara presisi mendapatkan highlight <code>active</code> / <code>here</code> sesuai rute aktif.',
    'pages.operasional.checklist-qa-smoke-test.item_3' => '<strong>Mobile Drawer:</strong> Menu navigasi dapat dibuka dan ditutup dengan lancar di layar seluler via mobile drawer.',
    'pages.operasional.checklist-qa-smoke-test.item_4' => '<strong>Responsive Wrapper:</strong> Seluruh tabel data dibungkus <code>&lt;div class="table-responsive"&gt;</code> sehingga scroll horizontal berfungsi di HP/tablet.',
    'pages.operasional.checklist-qa-smoke-test.item_5' => '<strong>Preservasi Lebar Kolom:</strong> Elemen <code>&lt;th&gt;</code> menggunakan kelas minimum width bawaan Metronic (<code>min-w-200px</code>, <code>min-w-150px</code>).',
    'pages.operasional.checklist-qa-smoke-test.item_6' => '<strong>Layout Partial Cleanliness:</strong> Partial tab tidak mengandung tag <code>@@endsection</code>, <code>@@extends</code>, atau penutup <code>&lt;/div&gt;</code> utama yang memotong footer.',
    'pages.operasional.checklist-qa-smoke-test.item_7' => '<strong>Notifikasi Sukses CRUD:</strong> Penambahan &amp; pembaharuan data memicu notifikasi <code>SwalHelper.success()</code>.',
    'pages.operasional.checklist-qa-smoke-test.item_8' => '<strong>Konfirmasi Hapus:</strong> Pengapusan data memicu dialog konfirmasi <code>SwalHelper.confirmDelete()</code> sebelum request dikirim.',
    'pages.operasional.checklist-qa-smoke-test.item_9' => '<strong>Handling Error 422 XHR:</strong> Kegagalan validasi AJAX menampilkan daftar pesan error via <code>SwalHelper.validationError(xhr)</code>.',
    'pages.operasional.checklist-qa-smoke-test.item_10' => '<strong>Icon-only Tooltips:</strong> Seluruh <code>btn-icon</code> memiliki atribut <code>data-bs-toggle="tooltip" data-bs-placement="top" title="..."</code>.',
    'pages.operasional.checklist-qa-smoke-test.item_11' => '<strong>Modal Trigger Wrapper:</strong> Tombol pemicu modal dibungkus tag <code>&lt;span data-bs-toggle="tooltip" ...&gt;</code> untuk mencegah konflik atribut.',
    'pages.operasional.checklist-qa-smoke-test.item_12' => '<strong>100% Bahasa Inggris (en):</strong> Saat beralih ke locale <code>en</code>, tidak ada teks Bahasa Indonesia yang tersisa pada menu maupun isi halaman.',
    'pages.operasional.checklist-qa-smoke-test.item_13' => '<strong>100% Bahasa Indonesia (id):</strong> Saat beralih ke locale <code>id</code>, seluruh judul, tombol, dan instruksi tampil rapi dalam Bahasa Indonesia.',
    'pages.operasional.checklist-qa-smoke-test.item_14' => '<strong>Pembersihan Cache View &amp; Config:</strong> Jalankan <code>php artisan optimize:clear</code> dan tes ulang aplikasi dari kondisi bersih.',
    'pages.operasional.checklist-qa-smoke-test.step_1' => '1. Jalankan pengujian navigasi &amp; responsivitas tampilan (desktop &amp; mobile).',
    'pages.operasional.checklist-qa-smoke-test.step_2' => '2. Uji alur CRUD, SwalHelper, validasi 422 XHR, dan konfirmasi hapus.',
    'pages.operasional.checklist-qa-smoke-test.step_3' => '3. Uji beralih bahasa (en &amp; id) untuk memastikan 100% paritas bilingual.',
    'pages.operasional.checklist-qa-smoke-test.step_4' => '4. Bersihkan cache dengan php artisan optimize:clear sebelum menyetujui rilis.',
    'pages.operasional.checklist-qa-smoke-test.note_1' => 'Fitur dilarang dirilis jika ada 1 saja item checklist di atas yang gagal! Seluruh 5 kategori pengujian harus bernilai PASS.',

    // Pages - Operasional Playbook Incident Response
    'pages.operasional.playbook-incident-response.hero_title' => 'Panduan Operasional: Playbook Incident Response',
    'pages.operasional.playbook-incident-response.hero_lead' => 'Prosedur standar penanganan insiden produksi (Sev-1 hingga Sev-4), matriks peran war-room, alur mitigasi cepat 15-menit, template komunikasi stakeholder, perintah CLI darurat, dan analisis post-mortem.',
    'pages.operasional.playbook-incident-response.lead' => 'Panduan taktis operasional tim engineering dalam merespon dan memitigasi insiden produksi secara terstruktur dan terukur.',
    'pages.operasional.playbook-incident-response.chip_1' => 'Sev-1 to Sev-4 Triage',
    'pages.operasional.playbook-incident-response.chip_2' => 'War-Room Role Matrix',
    'pages.operasional.playbook-incident-response.chip_3' => '15-Min Rapid Mitigation',
    'pages.operasional.playbook-incident-response.chip_4' => 'Blameless Post-Mortem',
    'pages.operasional.playbook-incident-response.heading_1' => 'Peran & Tanggung Jawab Tim Incident (War-Room Roles)',
    'pages.operasional.playbook-incident-response.heading_2' => 'Matriks Tingkat Keparahan Insiden (Severity Level)',
    'pages.operasional.playbook-incident-response.heading_3' => 'Timeline Respon Cepat 15-Menit Insiden Sev-1 (Critical Playbook)',
    'pages.operasional.playbook-incident-response.heading_4' => 'Timeline Respon Cepat 15-Menit Insiden Sev-2 (Major Playbook)',
    'pages.operasional.playbook-incident-response.heading_5' => 'Prosedur Penanganan Insiden Sev-3 & Sev-4 (Medium/Low Playbook)',
    'pages.operasional.playbook-incident-response.heading_6' => 'Template Komunikasi Broadcast Stakeholder',
    'pages.operasional.playbook-incident-response.heading_7' => 'Perintah CLI Mitigasi Darurat (Emergency Operations)',
    'pages.operasional.playbook-incident-response.heading_8' => 'Alur Post-Mortem & Tindakan Pencegahan (Blameless Review)',
    'pages.operasional.playbook-incident-response.item_1' => '<strong>Incident Commander (IC):</strong> Memimpin keputusan, menetapkan severity status, dan menentukan prioritas aksi mitigasi.',
    'pages.operasional.playbook-incident-response.item_2' => '<strong>Ops Lead (Backend/Infra):</strong> Mengesekusi aksi teknis darurat (rollback release, isolasi traffic, restart worker, feature flag).',
    'pages.operasional.playbook-incident-response.item_3' => '<strong>Comms Lead:</strong> Mengirimkan update status resmi berkala ke stakeholder internal dan pengguna.',
    'pages.operasional.playbook-incident-response.item_4' => '<strong>Scribe:</strong> Mencatat kronologi timeline insiden, keputusan kunci, log error, dan bukti pendukung (evidence).',
    'pages.operasional.playbook-incident-response.item_5' => '<strong>Sev-1 (Critical):</strong> Sistem down total, terjadi kebocoran data, atau transaksi inti gagal total. Butuh war-room penuh &amp; respon &lt; 5 menit.',
    'pages.operasional.playbook-incident-response.item_6' => '<strong>Sev-2 (Major):</strong> Fitur penting terganggu tetapi ada workaround parsial. Respon &lt; 15 menit.',
    'pages.operasional.playbook-incident-response.item_7' => '<strong>Sev-3 (Medium):</strong> Bugs fitur non-kritis atau degradasi performa minor. Respon &lt; 2 jam.',
    'pages.operasional.playbook-incident-response.item_8' => '<strong>Sev-4 (Low):</strong> Glitch kosmetik UI atau kesalahan minor tanpa dampak bisnis. Dijadwalkan pada sprint backlog.',
    'pages.operasional.playbook-incident-response.item_9' => '<strong>Standard Update Broadcast:</strong> [STATUS: INVESTIGATING/MITIGATED] Sev-X Insiden [Nama Modul]. Dampak: [Detail Dampak User]. Aksi: [Aksi Berjalan]. ETA Update Berikutnya: [Waktu].',
    'pages.operasional.playbook-incident-response.item_10' => '<strong>Metode Root Cause Analysis (5-Whys):</strong> Menemukan akar masalah utama tanpa menyalahkan individu (blameless Culture).',
    'pages.operasional.playbook-incident-response.item_11' => '<strong>Pencatatan Action Items:</strong> Menetapkan owner dan tenggat waktu perbaikan permanen pasca-insiden.',
    'pages.operasional.playbook-incident-response.step_1' => '1. Deteksi &amp; Deklarasi Severity oleh Incident Commander (0-5 menit).',
    'pages.operasional.playbook-incident-response.step_2' => '2. Pembentukan War-Room &amp; Eksekusi Mitigasi Tercepat oleh Ops Lead (5-10 menit).',
    'pages.operasional.playbook-incident-response.step_3' => '3. Verifikasi Dampak User &amp; Broadcast Update Resmi #1 oleh Comms Lead (10-15 menit).',
    'pages.operasional.playbook-incident-response.step_4' => '4. Pelaksanaan Blameless Post-Mortem &amp; penetapan Action Items (maksimal 48 jam pasca-insiden).',
    'pages.operasional.playbook-incident-response.note_1' => 'Prioritas utama saat insiden aktif adalah memulihkan layanan (mitigasi tercepat), BUKAN mencari akar masalah utama di tengah insiden.',
];



